using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF9 renamed the discriminator property from "Discriminator" to "$type".
            // Preserve the old name so existing 500K documents remain readable
            // and direct SQL queries filtering on c.Discriminator keep working.
            entity.HasDiscriminator<string>("Discriminator");

            // EF9 changed the id format from "EntityType|KeyValue" to just "KeyValue".
            // Preserve the old format so existing documents are found by key.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();
        });
    }

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        base.OnConfiguring(options);
    }
}

