             // BREAKING CHANGE 1 — Discriminator rename
             // EF9 renamed the discriminator JSON property from "Discriminator" to "$type".
             // Preserve the old name so existing 500K documents remain readable
             // and direct SQL queries (c.Discriminator = 'Product') keep working.
             entity.HasDiscriminator<string>("Discriminator");

             // BREAKING CHANGE 2 — id format
             // EF8 stored id as "Product|123"; EF9 stores just "123".
             // Map our explicit CosmosId property to the JSON "id" so existing
             // documents are found on point-reads and queries.
             entity.Property(p => p.CosmosId).ToJsonProperty("id");
             entity.HasKey(p => p.CosmosId);

             // BREAKING CHANGE 3 — HasIndex not supported for Cosmos
             // The previous HasIndex(p => p.Sku) compiled but was silently ignored
             // by EF8. EF9 may throw at model validation. Removed.
         });
     }
 }

 class Product
 {
     // Cosmos "id" — preserves EF8 format "Product|<key>"
     public string CosmosId { get; set; } = "";
     public int Id { get; set; }
     public string Sku { get; set; } = "";
 }

